import{_ as e,o as t,c as l,ag as i}from"./chunks/framework.CbQjVMS6.js";const p=JSON.parse('{"title":"🎸 第一周任务书：黑盒白盒化 (Operation White Box)","description":"","frontmatter":{},"headers":[],"relativePath":"PaiSmart/总览规划.md","filePath":"PaiSmart/总览规划.md","lastUpdated":null}'),r={name:"PaiSmart/总览规划.md"};function a(s,o,n,c,d,g){return t(),l("div",null,[...o[0]||(o[0]=[i('<h1 id="🎸-第一周任务书-黑盒白盒化-operation-white-box" tabindex="-1">🎸 第一周任务书：黑盒白盒化 (Operation White Box) <a class="header-anchor" href="#🎸-第一周任务书-黑盒白盒化-operation-white-box" aria-label="Permalink to &quot;🎸 第一周任务书：黑盒白盒化 (Operation White Box)&quot;">​</a></h1><blockquote><p>[!abstract] <strong>本周战略目标</strong><strong>“去魅”</strong>。 目前这个项目对你来说是一个运转中的“黑盒子”，你知道输入什么、输出什么，但不知道中间发生了什么。 本周不要求你写一行新代码，但要求你<strong>像法医一样解剖现有的代码</strong>。</p><p><strong>验收标准</strong>：随便指着架构图上的一个箭头（比如 Kafka 到 ES），你能流利地说出数据是以什么格式流动的，以及为什么要这样流。</p></blockquote><hr><h2 id="🏔️-核心高地一-基础设施与配置审计-infrastructure-audit" tabindex="-1">🏔️ 核心高地一：基础设施与配置审计 (Infrastructure Audit) <a class="header-anchor" href="#🏔️-核心高地一-基础设施与配置审计-infrastructure-audit" aria-label="Permalink to &quot;🏔️ 核心高地一：基础设施与配置审计 (Infrastructure Audit)&quot;">​</a></h2><p>这部分是面试的“前菜”，面试官会通过这些问题判断你对技术选型的理解深度。不要只看表面，要看懂“为什么”。</p><ul><li><p>[ ] <strong>依赖关系深度扫描 (<code>pom.xml</code>)</strong></p><ul><li><strong>LangChain4j</strong>：项目用了哪个版本？它集成了哪些大模型的 SDK？(OpenAI? Ollama?)。</li><li><strong>Apache Tika</strong>：重点关注 <code>tika-parsers</code>。去查一下，它默认支持哪些格式？是否引入了 <code>tesseract</code> (OCR) 相关的依赖？(这决定了你的系统能不能读扫描版 PDF)。</li><li><strong>Elasticsearch Client</strong>：是用老旧的 <code>RestHighLevelClient</code> 还是新的 <code>ElasticsearchClient</code>？这在写查询语句时完全不同。</li></ul></li><li><p>[ ] <strong>配置文件逻辑解构 (<code>application.yml</code>)</strong></p><ul><li><strong>Kafka 生产参数</strong>：重点看 <code>acks</code>、<code>retries</code>、<code>batch-size</code>。 <ul><li><em>思考任务</em>：目前的配置是追求“高吞吐”还是“不丢失数据”？如果不记得这些参数的含义，去搜，然后标注在旁边。</li></ul></li><li><strong>Redis 数据结构预判</strong>：看配置，结合业务猜测。 <ul><li>用了 <code>String</code> 做缓存吗？</li><li>用了 <code>Bitmap</code> 吗？(如果有分片上传)。</li><li>用了 <code>ZSet</code> 吗？(如果有排行榜)。</li></ul></li><li><strong>线程池配置</strong>：项目里有没有配置自定义的 <code>ThreadPoolTaskExecutor</code>？如果有，核心线程数是多少？(这关系到异步处理的并发能力)。</li></ul></li></ul><hr><h2 id="🏔️-核心高地二-异步文件处理流水线-the-async-pipeline" tabindex="-1">🏔️ 核心高地二：异步文件处理流水线 (The Async Pipeline) <a class="header-anchor" href="#🏔️-核心高地二-异步文件处理流水线-the-async-pipeline" aria-label="Permalink to &quot;🏔️ 核心高地二：异步文件处理流水线 (The Async Pipeline)&quot;">​</a></h2><p>这是你简历上<strong>最有含金量</strong>的模块（Kafka 解耦 + Tika 解析）。你必须能在大脑里重现一个 PDF 被“肢解”的全过程。</p><ul><li>[ ] <strong>追踪目标：一个 10MB 的 PDF 文件</strong><ul><li><strong>阶段 1：主线程的逃离 (Controller -&gt; Producer)</strong><ul><li><strong>核心任务</strong>：找到 <code>Controller</code> 接收文件后，是如何把任务“甩”给 Kafka 的。</li><li><em>深度挖掘</em>：发给 Kafka 的消息体 (Message Payload) 究竟长什么样？ <ul><li>是 <code>{ &quot;fileId&quot;: &quot;123&quot;, &quot;path&quot;: &quot;/minio/...&quot; }</code> 这种轻量级引用？</li><li>还是直接把文件流塞进去了？(如果是后者，这是设计缺陷，要记下来)。</li></ul></li></ul></li><li><strong>阶段 2：消费者的吞吐 (Consumer -&gt; Tika)</strong><ul><li><strong>核心任务</strong>：找到 <code>@KafkaListener</code>。观察这里是否开启了<strong>多线程消费</strong>？</li><li><em>深度挖掘</em>：<code>Tika</code> 解析文件时，是把整个文件加载进内存，还是用流式读取？(去 Tika 的调用代码里看)。如果是大文件，会不会 OOM (内存溢出)？</li></ul></li><li><strong>阶段 3：向量化的变身 (Text -&gt; Vector)</strong><ul><li><strong>核心任务</strong>：找到 Embedding 模型的调用点。</li><li><em>深度挖掘</em>：一段 500 字的文本，变成了一个多长的数组？(比如 1024 维)。这个数组最后是怎么存进 ES 的？(查看 ES 的 <code>Mapping</code> 定义，看 <code>dense_vector</code> 字段)。</li></ul></li></ul></li></ul><hr><h2 id="🏔️-核心高地三-rag-混合检索逻辑-hybrid-search-logic" tabindex="-1">🏔️ 核心高地三：RAG 混合检索逻辑 (Hybrid Search Logic) <a class="header-anchor" href="#🏔️-核心高地三-rag-混合检索逻辑-hybrid-search-logic" aria-label="Permalink to &quot;🏔️ 核心高地三：RAG 混合检索逻辑 (Hybrid Search Logic)&quot;">​</a></h2><p>这是区分“玩具 Demo”和“企业级应用”的分水岭。面试官会问你：“为什么不用纯向量检索？”</p><ul><li>[ ] <strong>追踪目标：用户的一个提问“Spring Boot 是什么”</strong><ul><li><strong>阶段 1：查询意图理解</strong><ul><li><strong>核心任务</strong>：代码有没有对用户的问题做预处理？(比如分词、去停用词、或者用 LLM 改写问题)。</li></ul></li><li><strong>阶段 2：ES 查询构建 (最关键！)</strong><ul><li><strong>核心任务</strong>：在 Debug 模式下，拦截程序发给 ES 的 <code>Query DSL</code> (查询语句)。</li><li><em>深度挖掘</em>： <ul><li>是否同时使用了 <code>match</code> (关键字检索) 和 <code>knn</code> (向量检索)？</li><li>它们的权重 (<code>boost</code>) 分别是多少？</li><li>有没有用 <code>min_score</code> 过滤掉相关度低的结果？</li></ul></li></ul></li><li><strong>阶段 3：Prompt 拼装</strong><ul><li><strong>核心任务</strong>：找到最后发给大模型的 Prompt 模板。</li><li><em>深度挖掘</em>：如果检索回来的文档片段太多，超过了 Token 限制，代码里有没有做<strong>截断</strong>处理？</li></ul></li></ul></li></ul><hr><h2 id="🚩-本周交付物-deliverables" tabindex="-1">🚩 本周交付物 (Deliverables) <a class="header-anchor" href="#🚩-本周交付物-deliverables" aria-label="Permalink to &quot;🚩 本周交付物 (Deliverables)&quot;">​</a></h2><p>周日晚上，你应该拥有以下两样东西：</p><ol><li><strong>一张全景架构图 (Visio / ProcessOn / Draw.io)</strong><ul><li>画出数据流向，并在关键节点（Kafka、Redis、ES）旁边标注出它在这里的<strong>作用</strong>和<strong>关键配置</strong>。</li></ul></li><li><strong>一份“踩坑与疑问”清单</strong><ul><li>记录下你阅读代码时发现的“奇怪写法”或“潜在 Bug”。</li><li>例如：“我看代码里 Tika 解析是在消费者主线程做的，如果解析卡死，会不会导致消费者掉线？”(这种问题非常有价值！)。</li></ul></li></ol><hr><div class="tip custom-block github-alert"><p class="custom-block-title">**Kasumi (Leader) 的叮嘱**</p><p></p><p>这周的任务不需要你写代码，但可能比写代码更累。 因为你要强迫自己去理解别人的思路。</p><p><strong>不要急着进入第二周</strong>。如果你连第一周的“查询构建逻辑”都没看懂，第二周的“重构”就无从谈起。</p><p>准备好开始了吗？打开 IDEA，这就是你的战场！</p></div>',20)])])}const h=e(r,[["render",a]]);export{p as __pageData,h as default};
